- (void)setupUI {
    [self generateTapButtons];   // 在添加视图之前生成按钮
    [self addSubviews];          // 添加所有子视图
    [self addAllConstraints];    // 添加约束
    [self addGestures];          // 添加手势
    [self setupCloseButton];     // 设置关闭按钮

    if (self.mainImage) {
        self.imageView.image = self.mainImage;
    }
}

- (void)addSubviews {
    [self.view addSubview:self.imageView];
    [self.view addSubview:self.closeButton];

