- (void)downloadZipFileWithURLString:(NSString *)urlString completion:(void (^)(NSString *zipFilePath))completion {
    NSURL *zipUrl = [NSURL URLWithString:urlString];
    if (!zipUrl) {
        NSLog(@"Invalid URL provided.");
        return;
    }

    // 提取压缩包的名字
    NSString *originalFilename = [self extractOriginalFilenameFromURL:zipUrl];
    if (originalFilename == nil) {
        originalFilename = @"DynamicPopupZip.zip"; // 标准压缩包名
    }

    // 使用WBStorageManager中cacheRoot作为压缩包存储位置
    NSString *zipFilePath = [[WBStorageManager sharedManager].cacheRoot stringByAppendingPathComponent:originalFilename];

    // 如果存在同名文件就进行删除，使用新的资源
    if ([[NSFileManager defaultManager] fileExistsAtPath:zipFilePath]) {
        NSError *deleteError;
        if (![[NSFileManager defaultManager] removeItemAtPath:zipFilePath error:&deleteError]) {
            NSLog(@"Error deleting existing file: %@", deleteError);
            return;
        }
        NSLog(@"Existing file deleted: %@", zipFilePath);
    }

    // 下载压缩包
    NSURLSession *session = [NSURLSession sharedSession];
    NSURLSessionDownloadTask *downloadTask = [session downloadTaskWithURL:zipUrl completionHandler:^(NSURL *location, NSURLResponse *response, NSError *error) {
        if (error) {
            NSLog(@"Error downloading the file: %@", error);
            return;
        }
        // 移动到指定文件
        NSError *moveError;
        [[NSFileManager defaultManager] moveItemAtURL:location toURL:[NSURL fileURLWithPath:zipFilePath] error:&moveError];
        if (moveError) {
            NSLog(@"Error moving the file: %@", moveError);
            return;
        }

        NSLog(@"File downloaded successfully to: %@", zipFilePath);

        // 当下载完成并且文件移动成功后，调用completion回调，将文件路径传回
        completion(zipFilePath);
    }];

    [downloadTask resume];
}

- (NSString *)extractOriginalFilenameFromURL:(NSURL *)url {
    NSString *lastPathComponent = [url lastPathComponent];
    if ([lastPathComponent isEqualToString:@""]) {
        // 如果提取不到压缩包的名字，就返回 nil
        return nil;
    }
    return lastPathComponent;
}


